"use client";

import { useState, useCallback, useEffect } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import { useInfiniteQuery } from "@tanstack/react-query";
import { motion, AnimatePresence } from "framer-motion";
import { SlidersHorizontal, X, LayoutGrid, List } from "lucide-react";
import { listingsService } from "@/services/listings.service";
import { searchService } from "@/services/search.service";
import { ListingCard } from "@/features/listings/listing-card";
import { ListingCardSkeleton } from "@/components/ui/skeleton";
import { FilterSidebar } from "@/features/search/filter-sidebar";
import { SearchBar } from "@/features/search/search-bar";
import { Button } from "@/components/ui/button";
import type { SearchFilters, Listing } from "@/types";

const PAGE_SIZE = 12;

const SORT_OPTIONS = [
  { value: "created_at_desc", label: "Newest first" },
  { value: "price_asc", label: "Price: Low to High" },
  { value: "price_desc", label: "Price: High to Low" },
  { value: "year_desc", label: "Year: Newest" },
] as const;

export default function ListingsPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const [showFilters, setShowFilters] = useState(false);
  const [view, setView] = useState<"grid" | "list">("grid");

  const [filters, setFilters] = useState<SearchFilters>({
    query: searchParams.get("q") ?? undefined,
    sort: "created_at_desc",
    page: 1,
    size: PAGE_SIZE,
  });

  const hasQuery = Boolean(filters.query);

  const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } = useInfiniteQuery({
    queryKey: ["listings", filters],
    queryFn: ({ pageParam = 1 }) => {
      const f = { ...filters, page: pageParam as number };
      if (hasQuery) return searchService.search(f);
      return listingsService.list({ ...f, status: "active" });
    },
    initialPageParam: 1,
    getNextPageParam: (last, pages) => {
      const loaded = pages.flatMap((p) => p.items).length;
      return loaded < last.total ? pages.length + 1 : undefined;
    },
  });

  const allListings = data?.pages.flatMap((p) => p.items) ?? [];
  const total = data?.pages[0]?.total ?? 0;

  const handleFiltersChange = useCallback((f: SearchFilters) => {
    setFilters(f);
  }, []);

  const handleSearch = useCallback((query: string) => {
    setFilters((f) => ({ ...f, query: query || undefined, page: 1 }));
    const params = new URLSearchParams();
    if (query) params.set("q", query);
    router.replace(`/main/listings?${params.toString()}`, { scroll: false });
  }, [router]);

  const activeFilterCount = [
    filters.vehicle_type,
    filters.condition,
    filters.min_price,
    filters.min_year,
    filters.max_year,
    filters.make,
    filters.location,
  ].filter(Boolean).length;

  return (
    <div className="flex flex-col gap-6">
      {/* Top bar */}
      <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center">
        <div className="flex-1 w-full">
          <SearchBar
            defaultValue={filters.query ?? ""}
            onSearch={handleSearch}
            placeholder="Search by make, model, or keyword…"
          />
        </div>
        <div className="flex items-center gap-2 shrink-0">
          {/* Filter toggle (mobile) */}
          <Button
            variant="secondary"
            size="sm"
            onClick={() => setShowFilters(true)}
            className="lg:hidden"
          >
            <SlidersHorizontal className="h-4 w-4" />
            Filters
            {activeFilterCount > 0 && (
              <span className="ml-1 px-1.5 py-0.5 rounded bg-amber-500/20 text-amber-400 text-xs">
                {activeFilterCount}
              </span>
            )}
          </Button>

          {/* Sort */}
          <select
            value={filters.sort ?? "created_at_desc"}
            onChange={(e) => setFilters((f) => ({ ...f, sort: e.target.value as SearchFilters["sort"], page: 1 }))}
            className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-[var(--radius-sm)] px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-amber-500/50"
          >
            {SORT_OPTIONS.map((o) => (
              <option key={o.value} value={o.value}>{o.label}</option>
            ))}
          </select>

          {/* View toggle */}
          <div className="flex border border-[var(--color-border)] rounded-[var(--radius-sm)] overflow-hidden">
            <button
              onClick={() => setView("grid")}
              className={`p-2 transition-colors ${view === "grid" ? "bg-amber-500/20 text-amber-400" : "text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]"}`}
            >
              <LayoutGrid className="h-4 w-4" />
            </button>
            <button
              onClick={() => setView("list")}
              className={`p-2 transition-colors ${view === "list" ? "bg-amber-500/20 text-amber-400" : "text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]"}`}
            >
              <List className="h-4 w-4" />
            </button>
          </div>
        </div>
      </div>

      <div className="flex gap-8">
        {/* Desktop filter sidebar */}
        <aside className="hidden lg:block w-60 shrink-0">
          <FilterSidebar filters={filters} onChange={handleFiltersChange} />
        </aside>

        {/* Listings grid */}
        <div className="flex-1 min-w-0">
          {/* Result count */}
          <div className="flex items-center justify-between mb-4">
            <p className="text-sm text-[var(--color-text-muted)]">
              {isLoading ? (
                <span className="skeleton h-4 w-24 inline-block rounded" />
              ) : (
                <>
                  <span className="text-[var(--color-text-primary)] font-medium">{total.toLocaleString()}</span>{" "}
                  vehicle{total !== 1 ? "s" : ""} found
                </>
              )}
            </p>
            {activeFilterCount > 0 && (
              <button
                onClick={() => setFilters({ query: filters.query, sort: filters.sort, page: 1, size: PAGE_SIZE })}
                className="flex items-center gap-1 text-xs text-amber-400 hover:text-amber-300 transition-colors"
              >
                <X className="h-3 w-3" /> Clear filters
              </button>
            )}
          </div>

          {isLoading ? (
            <div className={`grid gap-4 ${view === "grid" ? "grid-cols-1 sm:grid-cols-2 xl:grid-cols-3" : "grid-cols-1"}`}>
              {Array.from({ length: 6 }).map((_, i) => <ListingCardSkeleton key={i} />)}
            </div>
          ) : allListings.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-center">
              <div className="text-5xl mb-4">🔍</div>
              <p className="text-[var(--color-text-secondary)] font-medium">No vehicles found</p>
              <p className="text-sm text-[var(--color-text-muted)] mt-1">
                Try adjusting your filters or search terms
              </p>
            </div>
          ) : (
            <div className={`grid gap-4 ${view === "grid" ? "grid-cols-1 sm:grid-cols-2 xl:grid-cols-3" : "grid-cols-1"}`}>
              {allListings.map((listing, i) => (
                <motion.div
                  key={listing.id}
                  initial={{ opacity: 0, y: 12 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: Math.min(i * 0.04, 0.3) }}
                >
                  <ListingCard listing={listing} />
                </motion.div>
              ))}
            </div>
          )}

          {/* Load more */}
          {hasNextPage && (
            <div className="flex justify-center mt-8">
              <Button
                variant="secondary"
                size="lg"
                loading={isFetchingNextPage}
                onClick={() => fetchNextPage()}
              >
                Load more vehicles
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Mobile filter drawer */}
      <AnimatePresence>
        {showFilters && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setShowFilters(false)}
              className="fixed inset-0 bg-black/60 z-40 lg:hidden"
            />
            <motion.div
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ type: "spring", damping: 30, stiffness: 300 }}
              className="fixed right-0 top-0 h-full w-80 bg-[var(--color-surface)] border-l border-[var(--color-border)] z-50 overflow-y-auto p-6 lg:hidden"
            >
              <FilterSidebar
                filters={filters}
                onChange={handleFiltersChange}
                onClose={() => setShowFilters(false)}
              />
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}
