import { cn } from "@/lib/utils";

type BadgeVariant = "default" | "amber" | "success" | "danger" | "info" | "outline";

const styles: Record<BadgeVariant, string> = {
  default:  "bg-[var(--color-elevated)] text-[var(--color-text-secondary)] border border-[var(--color-border)]",
  amber:    "bg-amber-500/15 text-amber-400 border border-amber-500/25",
  success:  "bg-green-500/15 text-green-400 border border-green-500/25",
  danger:   "bg-red-500/15 text-red-400 border border-red-500/25",
  info:     "bg-blue-500/15 text-blue-400 border border-blue-500/25",
  outline:  "bg-transparent border border-[var(--color-border)] text-[var(--color-text-secondary)]",
};

export function Badge({
  children,
  variant = "default",
  className,
}: {
  children: React.ReactNode;
  variant?: BadgeVariant;
  className?: string;
}) {
  return (
    <span className={cn("inline-flex items-center gap-1 px-2 py-0.5 rounded-md text-xs font-medium", styles[variant], className)}>
      {children}
    </span>
  );
}
