"use client";

import { useCallback } from "react";
import { motion } from "framer-motion";
import { X, SlidersHorizontal } from "lucide-react";
import { Button } from "@/components/ui/button";
import type { SearchFilters, VehicleType, Condition } from "@/types";

const VEHICLE_TYPES: { value: VehicleType; label: string }[] = [
  { value: "car", label: "Car" },
  { value: "bike", label: "Bike" },
  { value: "truck", label: "Truck" },
  { value: "van", label: "Van" },
];

const CONDITIONS: { value: Condition; label: string }[] = [
  { value: "new", label: "New" },
  { value: "used", label: "Used" },
  { value: "certified", label: "Certified Pre-Owned" },
];

const PRICE_RANGES = [
  { label: "Under $10K", min: 0, max: 10000 },
  { label: "$10K – $25K", min: 10000, max: 25000 },
  { label: "$25K – $50K", min: 25000, max: 50000 },
  { label: "$50K – $100K", min: 50000, max: 100000 },
  { label: "$100K+", min: 100000, max: undefined },
];

const CURRENT_YEAR = new Date().getFullYear();
const YEARS = Array.from({ length: 30 }, (_, i) => CURRENT_YEAR - i);

interface FilterSidebarProps {
  filters: SearchFilters;
  onChange: (filters: SearchFilters) => void;
  onClose?: () => void;
}

export function FilterSidebar({ filters, onChange, onClose }: FilterSidebarProps) {
  const set = useCallback(
    (patch: Partial<SearchFilters>) => onChange({ ...filters, ...patch, page: 1 }),
    [filters, onChange]
  );

  const reset = () => onChange({ page: 1 });

  const activeCount = [
    filters.vehicle_type,
    filters.condition,
    filters.min_price,
    filters.min_year,
    filters.max_year,
    filters.make,
    filters.location,
  ].filter(Boolean).length;

  return (
    <aside className="w-full">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-2">
          <SlidersHorizontal className="h-4 w-4 text-amber-400" />
          <span className="font-display tracking-widest text-sm">FILTERS</span>
          {activeCount > 0 && (
            <span className="px-1.5 py-0.5 rounded bg-amber-500/20 text-amber-400 text-xs font-medium">
              {activeCount}
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {activeCount > 0 && (
            <button onClick={reset} className="text-xs text-[var(--color-text-muted)] hover:text-amber-400 transition-colors">
              Clear all
            </button>
          )}
          {onClose && (
            <button onClick={onClose} className="text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] lg:hidden">
              <X className="h-4 w-4" />
            </button>
          )}
        </div>
      </div>

      <div className="space-y-6">
        {/* Vehicle Type */}
        <FilterSection label="Vehicle Type">
          <div className="grid grid-cols-2 gap-2">
            {VEHICLE_TYPES.map(({ value, label }) => (
              <FilterChip
                key={value}
                active={filters.vehicle_type === value}
                onClick={() => set({ vehicle_type: filters.vehicle_type === value ? undefined : value })}
              >
                {label}
              </FilterChip>
            ))}
          </div>
        </FilterSection>

        {/* Condition */}
        <FilterSection label="Condition">
          <div className="space-y-2">
            {CONDITIONS.map(({ value, label }) => (
              <label key={value} className="flex items-center gap-3 cursor-pointer group">
                <div
                  className={`w-4 h-4 rounded border transition-all ${
                    filters.condition === value
                      ? "bg-amber-500 border-amber-500"
                      : "border-[var(--color-border)] group-hover:border-amber-500/50"
                  }`}
                  onClick={() => set({ condition: filters.condition === value ? undefined : value })}
                >
                  {filters.condition === value && (
                    <svg viewBox="0 0 16 16" fill="none" className="w-full h-full">
                      <path d="M3 8l3.5 3.5L13 5" stroke="black" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                  )}
                </div>
                <span className="text-sm text-[var(--color-text-secondary)] group-hover:text-[var(--color-text-primary)] transition-colors">
                  {label}
                </span>
              </label>
            ))}
          </div>
        </FilterSection>

        {/* Price Range */}
        <FilterSection label="Price Range">
          <div className="space-y-2">
            {PRICE_RANGES.map(({ label, min, max }) => {
              const active = filters.min_price === min && filters.max_price === max;
              return (
                <FilterChip
                  key={label}
                  active={active}
                  onClick={() =>
                    set(active ? { min_price: undefined, max_price: undefined } : { min_price: min, max_price: max })
                  }
                  className="w-full text-left"
                >
                  {label}
                </FilterChip>
              );
            })}
          </div>
        </FilterSection>

        {/* Year Range */}
        <FilterSection label="Year">
          <div className="flex items-center gap-2">
            <select
              value={filters.min_year ?? ""}
              onChange={(e) => set({ min_year: e.target.value ? +e.target.value : undefined })}
              className="flex-1 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-[var(--radius-sm)] px-2 py-1.5 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-amber-500/50"
            >
              <option value="">From</option>
              {YEARS.map((y) => <option key={y} value={y}>{y}</option>)}
            </select>
            <span className="text-[var(--color-text-muted)] text-xs">–</span>
            <select
              value={filters.max_year ?? ""}
              onChange={(e) => set({ max_year: e.target.value ? +e.target.value : undefined })}
              className="flex-1 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-[var(--radius-sm)] px-2 py-1.5 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-amber-500/50"
            >
              <option value="">To</option>
              {YEARS.map((y) => <option key={y} value={y}>{y}</option>)}
            </select>
          </div>
        </FilterSection>

        {/* Make */}
        <FilterSection label="Make / Brand">
          <input
            type="text"
            value={filters.make ?? ""}
            placeholder="e.g. Toyota, BMW…"
            onChange={(e) => set({ make: e.target.value || undefined })}
            className="w-full bg-[var(--color-surface)] border border-[var(--color-border)] rounded-[var(--radius-sm)] px-3 py-1.5 text-sm text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)] focus:outline-none focus:border-amber-500/50 transition-colors"
          />
        </FilterSection>

        {/* Location */}
        <FilterSection label="Location">
          <input
            type="text"
            value={filters.location ?? ""}
            placeholder="City or state…"
            onChange={(e) => set({ location: e.target.value || undefined })}
            className="w-full bg-[var(--color-surface)] border border-[var(--color-border)] rounded-[var(--radius-sm)] px-3 py-1.5 text-sm text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)] focus:outline-none focus:border-amber-500/50 transition-colors"
          />
        </FilterSection>

        {onClose && (
          <Button onClick={onClose} className="w-full" size="lg">
            Apply Filters
          </Button>
        )}
      </div>
    </aside>
  );
}

function FilterSection({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div>
      <p className="text-xs font-medium text-[var(--color-text-muted)] uppercase tracking-widest mb-3">{label}</p>
      {children}
    </div>
  );
}

function FilterChip({
  active,
  onClick,
  children,
  className,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
  className?: string;
}) {
  return (
    <motion.button
      onClick={onClick}
      whileTap={{ scale: 0.97 }}
      className={`px-3 py-1.5 rounded-[var(--radius-sm)] text-sm border transition-all ${
        active
          ? "bg-amber-500/20 border-amber-500/50 text-amber-400"
          : "bg-transparent border-[var(--color-border)] text-[var(--color-text-secondary)] hover:border-amber-500/30 hover:text-[var(--color-text-primary)]"
      } ${className ?? ""}`}
    >
      {children}
    </motion.button>
  );
}
