"use client";

import Image from "next/image";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";
import { MapPin, Gauge, Calendar, Edit2, Trash2 } from "lucide-react";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";
import { listingsService } from "@/services/listings.service";
import { formatPrice, formatMileage, timeAgo, imageUrl } from "@/lib/utils";
import type { Listing } from "@/types";

const conditionVariant = {
  new: "success",
  used: "default",
  certified: "amber",
} as const;

export function ListingCard({
  listing,
  index = 0,
  showActions = false,
}: {
  listing: Listing;
  index?: number;
  showActions?: boolean;
}) {
  const router = useRouter();
  const thumb = listing.images[0];

  const handleDelete = async (e: React.MouseEvent) => {
    e.preventDefault();
    if (!confirm("Delete this listing?")) return;
    try {
      await listingsService.delete(listing.id);
      toast.success("Listing removed");
      router.refresh();
    } catch {
      toast.error("Failed to delete listing");
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3, delay: index * 0.05 }}
    >
      <Link href={`/main/listings/${listing.id}`} className="block group">
        <article className="card overflow-hidden" aria-label={listing.title}>
          {/* Image */}
          <div className="relative h-48 bg-[var(--color-elevated)] overflow-hidden">
            {thumb ? (
              <Image
                src={imageUrl(thumb)}
                alt={listing.title}
                fill
                className="object-cover transition-transform duration-500 group-hover:scale-105"
                sizes="(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 33vw"
              />
            ) : (
              <div className="absolute inset-0 flex items-center justify-center">
                <span className="font-display text-5xl text-[var(--color-border)] tracking-wider">
                  {listing.make[0]}
                </span>
              </div>
            )}
            {/* Overlay gradient */}
            <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
            {/* Status badge */}
            {listing.status === "sold" && (
              <div className="absolute inset-0 bg-black/60 flex items-center justify-center">
                <span className="font-display text-3xl text-amber-400 tracking-widest border-2 border-amber-400/50 px-4 py-1">
                  SOLD
                </span>
              </div>
            )}
            <div className="absolute top-3 left-3">
              <Badge variant={conditionVariant[listing.condition]}>
                {listing.condition.toUpperCase()}
              </Badge>
            </div>
            <div className="absolute top-3 right-3 opacity-0 group-hover:opacity-100 transition-opacity">
              <Badge variant="amber">{listing.vehicle_type}</Badge>
            </div>
          </div>

          {/* Content */}
          <div className="p-4">
            <h3 className="font-display text-xl tracking-wide text-[var(--color-text-primary)] line-clamp-1 group-hover:text-amber-400 transition-colors">
              {listing.title}
            </h3>
            <p className="text-sm text-[var(--color-text-muted)] mt-0.5">
              {listing.make} {listing.model}
            </p>

            {/* Specs row */}
            <div className="flex items-center gap-3 mt-3 text-xs text-[var(--color-text-muted)]">
              <span className="flex items-center gap-1">
                <Calendar className="h-3 w-3" /> {listing.year}
              </span>
              <span className="flex items-center gap-1">
                <Gauge className="h-3 w-3" /> {formatMileage(listing.mileage)}
              </span>
              <span className="flex items-center gap-1 ml-auto">
                <MapPin className="h-3 w-3" /> {listing.location}
              </span>
            </div>

            {/* Price row */}
            <div className="flex items-center justify-between mt-3 pt-3 border-t border-[var(--color-border)]">
              <span className="font-mono text-lg font-medium text-amber-400">
                {formatPrice(listing.price)}
              </span>
              <span className="text-xs text-[var(--color-text-muted)]">
                {timeAgo(listing.created_at)}
              </span>
            </div>

            {showActions && (
              <div className="flex gap-2 mt-3 pt-3 border-t border-[var(--color-border)]">
                <Link
                  href={`/main/listings/${listing.id}/edit`}
                  onClick={(e) => e.stopPropagation()}
                  className="flex-1 flex items-center justify-center gap-1 py-1.5 text-xs border border-[var(--color-border)] rounded hover:border-amber-500/50 hover:text-amber-400 transition-colors"
                >
                  <Edit2 className="h-3 w-3" /> Edit
                </Link>
                <button
                  onClick={handleDelete}
                  className="flex-1 flex items-center justify-center gap-1 py-1.5 text-xs border border-[var(--color-border)] rounded hover:border-red-500/50 hover:text-red-400 transition-colors"
                >
                  <Trash2 className="h-3 w-3" /> Delete
                </button>
              </div>
            )}
          </div>
        </article>
      </Link>
    </motion.div>
  );
}
